    10→
    11→export function extractMeta(document: Document): Meta {
    12→  const title =
    13→    document.querySelector("meta[property='og:title']")?.getAttribute(
    14→      "content",
    15→    ) ??
    16→      document.querySelector("title")?.textContent ??
    17→      "";
    18→
    19→  const description =
    20→    document.querySelector("meta[property='og:description']")?.getAttribute(
    21→      "content",
    22→    ) ??
    23→      document.querySelector("meta[name='description']")?.getAttribute(
    24→        "content",
    25→      ) ??
    26→      "";
    27→
    28→  return { title: title.trim(), description: description.trim() };
    29→}
    30→
    31→export function extractContent(
    32→  document: Document,
    33→  html: string,
    34→  reader: boolean,
    35→): string {
    36→  if (reader) {
    37→    const article = new Readability(
    38→      document as unknown as globalThis.Document,
    39→    ).parse();
    40→    return article?.content ?? html;
    41→  }
    42→
    43→  for (
    44→    const tag of [
    45→      "script",
    46→      "style",
    47→      "noscript",
    48→      "nav",
    49→      "header",
    50→      "footer",
    51→      "aside",
    52→      "iframe",
    53→    ]
    54→  ) {
    55→    document.querySelectorAll(tag).forEach((el: Element) => el.remove());
    56→  }
    57→  return document.body?.innerHTML ?? html;
    58→}
