    60→export function parseDocument(html: string): Document {
    61→  const normalised = /^\s*<(!DOCTYPE|html)/i.test(html)
    62→    ? html
    63→    : `<html><body>${html}</body></html>`;
    64→  return parseHTML(normalised).document;
